function LxDreamTripCtrl:InitTouchs()
    self:AddTouch(TouchNames.On_TouchStart,self.OnTouchStart, self)
    self:AddTouch(TouchNames.On_TouchUp,self.OnTouchUp, self)

    self:AddTouch(TouchNames.On_SwipeStart, function(gesture)
        self:OnDragStart(gesture)
    end)

    self:AddTouch(TouchNames.On_SwipeEnd, function(gesture)
        self:OnDragEnd(gesture)
    end)

    self:AddTouch(TouchNames.On_Swipe, function(gesture)
        --if not self:CheckPlayerRoleIsIdle() then return end
        if self._touchNpc then self._touchNpc = nil end
        self:OnDrag(gesture)
    end)
end

---@param gesture Gesture
function LxDreamTripCtrl:OnTouchStart(gesture)
    if not self._dreamTripView then return end

    local gos = PJXUtil.TouchHitObjects(gesture.position, gesture.fingerIndex)
    if gos and gos.Count > 0 then
        local count = gos.Count - 1
        local go
        for i=0, count do
            go = gos[i]
            if go then
                if string.startswith(go.name, "Grid") then
                    self._touchNpc = go
                    local vec = go.transform.localScale
                    self._touchNpcVec = Vector3(vec.x,vec.y,vec.z)
                    go.transform.localScale = Vector3.New(0.98,0.98,0.98)
                    break
                elseif string.startswith(go.name, "TreeRoot") then
                    self._touchNpc = go
                    local vec = go.transform.localScale
                    self._touchNpcVec = Vector3(vec.x,vec.y,vec.z)
                    go.transform.localScale = Vector3.New(vec.x - 0.02,vec.y - 0.02,vec.z - 0.02)
                    break
                elseif string.startswith(go.name, "treeUpLevelRoot") then
                    self._touchNpc = go
                    local vec = go.transform.localScale
                    self._touchNpcVec = Vector3(vec.x,vec.y,vec.z)
                    go.transform.localScale = Vector3.New(vec.x - 0.2,vec.y - 0.2,vec.z - 0.2)
                    break
                end
            end
        end
    end
end

---@param gesture Gesture
function LxDreamTripCtrl:OnTouchUp(gesture)
    local touchNpc = self._touchNpc
    self._touchNpc = nil
    if touchNpc then
        local vec = self._touchNpcVec or Vector3.one
        touchNpc.transform.localScale = vec
    end
    self._touchNpcVec = nil

    local gos = PJXUtil.TouchHitObjects(gesture.position, gesture.fingerIndex)
    if gos and gos.Count > 0 then
        local count = gos.Count - 1
        local go
        for i=0, count do
            go = gos[i]
            if go and touchNpc == go then
                self:OnTouchClickNpc(go)
                break
            end
        end
    end
end

function LxDreamTripCtrl:OnTouchClickNpc(go)
    if string.startswith(go.name, "TreeRoot") then
        ShowPanel(UiNames.OnHook)
    elseif string.startswith(go.name, "treeUpLevelRoot") then
        ShowPanel(UiNames.OnHookUpLevel)
    else
        self:OnClickNpc(go)
    end
end

function LxDreamTripCtrl:OnClickNpc(go)
    if not self._dreamTripView then return end

    local id = self._dreamTripView:FindInstanceID(go.transform)
    ---@type LDreamTripUnitView
    local unitView = self._dreamTripView:GetUnitView(id)
    if not unitView then  return end

    local unitData = unitView:GetUnitData()
    if not unitData then return end

    local index = unitData.index
    local playerIndex = CtrlCenter.DreamTrip:GetDreamTripFinalPoint()
    if index and playerIndex and index ~= playerIndex then
        local pointObj = unitData.pointObj
        if pointObj then
            CtrlCenter.Instance:OpenPointDetails(pointObj.refId)
            CtrlCenter.Instance:PrintPointInfo(pointObj.refId,{
                pointRefId = pointObj.refId,
                pointObj = pointObj,
            })
        end
        return
    end

    local pointObj = unitData.pointObj
    if not pointObj then return end

    if pointObj.finish then
        CtrlCenter.Instance:OpenPointDetails(pointObj.refId)
        self:ResetExecute()
        return
    end

    local pointRefId = pointObj.refId

    CtrlCenter.Instance:OpenPointUI(pointRefId,{
        pointRefId = pointRefId,
        pointObj = pointObj,
    })
end

function LxDreamTripCtrl:OnDragStart()
end

