function LxDreamTripCtrl:OnDrag(gesture)
    local go = PJXUtil.TouchHitObject(gesture.position,gesture.fingerIndex)
    if go and go == self._mapRoot then
        --local position = gesture.position
        --local worldPos = LxUiHelper.GetSceneCamera():ScreenToWorldPoint(Vector3(position.x, position.y,0))
        self:OnDragMap(self._touchMoveSpeed * gesture.deltaPosition)
    end
end

function LxDreamTripCtrl:OnDragMap(deltaPosition)
    if not self._dreamTripView then return end
    if not self._dreamTripView:CheckIsFinish() then return end
    self._dreamTripView:AdjustMapPosition(deltaPosition)
end

