function LxDreamTripCtrl:InitDreamTripView()
    local dreamTripAdapter = MgrCenter.AdapterMgr:GetAdapter(LevelNames.DreamTrip)
    local mapTrans = dreamTripAdapter:GetMapTrans()
    self._mapRoot = mapTrans:Find('MapRoot').gameObject

    self:InitTouchs()
    self:InitEvents()

    local param = self:GetParam()
    local mapRefId = param.mapRefId

    local initCallBack = nil
    local playGridAni = param.playGridAni and true or false
    if self._isFirstLoad and not playGridAni then
        self._isFirstLoad = false
        playGridAni = true
    else
        initCallBack = function()
            self:SetGuideReady(true)
            FireEvent(EventNames.INSTANCE_MAPFINISHINITANI)
            FireEvent(EventNames.ON_MAP_GUIDE_READY, {levelName = LevelNames.DreamTrip})
        end
    end

    ShowPanel(UiNames.InstanceWorldMain,{
        mapRefId = mapRefId,
        initCallBack = initCallBack,
        battleFinish = param.battleFinish,
        triggerAutoPlayFunc = param.triggerAutoPlayFunc,
        isChangeMap = param.isChangeMap,
    })


    --- 初始化数据
    self:InitDreamTripMapData(mapRefId)

    local dreamTripView = require("LApp.gameplay.dreamTrip.view.LDreamTripView"):new()
    dreamTripView:Initialize()
    dreamTripView:SetPlayerAniStatus(playGridAni)
    dreamTripView:SetParam(param)
    dreamTripView:InitView()
    self._dreamTripView = dreamTripView



    self:StartTimer(_DRCtrlTimer.FrameRun, 0, true, -1, function()
        self:OnUpdate()
    end)
end

---@param mapRefId number
function LxDreamTripCtrl:InitDreamTripMapData(mapRefId)
    ---@type V_InsmapRef
    local mapRef = GameTable.InsmapRef[mapRefId]
    local dreamTripMapData = self._dreamTripMapData
    if not dreamTripMapData then
        dreamTripMapData = require("LApp.gameplay.dreamTrip.data.LDreamTripMapData"):new()
        self._dreamTripMapData = dreamTripMapData
    end
    local instanceMapObj = ModuleCenter.Instance:GetInstanceMapObj(mapRef.refId)
    dreamTripMapData:SetMapData(mapRef,instanceMapObj)
    dreamTripMapData:InitData()
    return dreamTripMapData
end

