function LxDreamTripCtrl:MoveNum(num,finalPoint,func)
    if not self._dreamTripMapData then return end
    if not self._dreamTripView then return end

    local dreamTripView = self._dreamTripView
    local index = self:GetDreamTripFinalPoint()
    local list = {}
    local newIndex = index + num
    local isStart = self._dreamTripMapData:CheckIsStart()
    if isStart then
        if num == 1 then
            num = 2
        end
        newIndex = num
    end
    local moveState = DreamTripMoveType.Normal
    local gridCount = self:GetGridCount()
    if newIndex > gridCount then
        for i = index,gridCount do
            table.insert(list,{
                pos = dreamTripView:GetGridRootPos(i),
                idx = i,
                moveState = moveState,
            })
        end
--[[        newIndex = newIndex - gridCount
        for i = 1,newIndex do
            table.insert(list,{
                pos = dreamTripView:GetLimitGridRootPos(i),
                idx = i,
                moveState = moveState,
            })
        end]]
        newIndex = gridCount
    else
        for i = index,newIndex do
            table.insert(list,{
                pos = dreamTripView:GetGridRootPos(i),
                idx = i,
                moveState = moveState,
            })
        end
    end

    ModuleCenter.Instance:SetInstanceMapFinalPoint(self._dreamTripMapData:GetMapRefId(),finalPoint)

    self._dreamTripMapData:SetMoveToIndex(newIndex)
    dreamTripView:SetMainRoleRunPosList(list,function()
        if self._dreamTripMapData then
            self._dreamTripMapData:UpdateIndex()
            if self._dreamTripView then
                local unitView = self._dreamTripView:GetUnitViewByIndex(newIndex)
                if not unitView then
                    self:ResetExecute()
                end
            end
        end
        if func then func() end
    end)
end

