function LxDreamTripCtrl:MovePortalPos(callback)
    local portalIndex = self:GetPortalTypeGridIndex()
    local gridCount = self:GetGridCount()
    local index = self:GetDreamTripFinalPoint()
    local list = {}
    local dreamTripView = self._dreamTripView
    local moveState = DreamTripMoveType.MoveEnd
    if portalIndex > index then
        for i = index,portalIndex do
            table.insert(list,{
                pos = dreamTripView:GetGridRootPos(i),
                idx = i,
                moveState = moveState,
            })
        end
    else
        for i = index,gridCount do
            table.insert(list,{
                pos = dreamTripView:GetGridRootPos(i),
                idx = i,
                moveState = moveState,
            })
        end
        for i = 1,portalIndex do
            table.insert(list,{
                pos = dreamTripView:GetGridRootPos(i),
                idx = i,
                moveState = moveState,
            })
        end
    end
    --ModuleCenter.Instance:SetInstanceMapFinalPoint(self._dreamTripMapData:GetMapRefId(),portalIndex)
    self._dreamTripMapData:SetMoveToIndex(portalIndex)
    dreamTripView:SetMainRoleRunPosList(list,function()
        if self._dreamTripMapData then self._dreamTripMapData:UpdateIndex() end
        if callback then callback() end
    end)
end

