---@return table<number,V_InsPlatformRef>
function LxDreamTripCtrl:GetInsPlatformList(mapRefId)
    local list = self._insPlatformRefList[mapRefId]
    if not list then
        list = {}
        local ref = GameTable.InsPlatformRef
        for k,v in pairs(ref) do
            if v.mapId == mapRefId then
                table.insert(list,v)
            end
        end
        table.sort(list,function(a, b) return a.gridNum < b.gridNum end)
        self._insPlatformRefList[mapRefId] = list
    end
    return list
end

function LxDreamTripCtrl:GetInsPlatformResourceList(mapRefId)
    local resourceList = self._insPlatformResourceList[mapRefId]
    if not resourceList then
        resourceList = {}
        local list = self:GetInsPlatformList(mapRefId)
        local resource,path,prefabName,resourceNum
        local pathList = {}
        for i,v in ipairs(list) do
            resource = string.split(v.platformShow,"/")
            resourceNum = #resource
            pathList = {}
            for idx = 1,resourceNum - 1 do
                table.insert(pathList,resource[idx])
            end
            path = table.concat(pathList,"/")
            prefabName = resource[resourceNum]
            resourceList[v.gridNum] = {
                path = path,prefabName = prefabName
            }
        end
        self._insPlatformResourceList[mapRefId] = resourceList
    end
    return resourceList
end

