---@return Vector2[]
function LxDreamTripCtrl:GetCameraRange()
    local cameraRangeX = self._cameraRangeX
    local cameraRangeY = self._cameraRangeY
    if not cameraRangeX and not cameraRangeY then
        local instanceBorder = GameTable.InsConfigRef["instanceBorder"]
        if instanceBorder and #instanceBorder > 0 then
            local rangeX = instanceBorder[1]
            cameraRangeX = Vector2(-rangeX,rangeX)

            local rangeY = instanceBorder[2]
            cameraRangeY = Vector2(-rangeY,rangeY)
        else
            cameraRangeX = Vector2(-5,5)
            cameraRangeY = Vector2(-3,3)
        end
        self._cameraRangeX = cameraRangeX
        self._cameraRangeY = cameraRangeY
    end
    return cameraRangeX,cameraRangeY
end


