---@param pointObj LxInstancePointObj
function LxDreamTripCtrl:CheckIsIgnoreFinishStatus(pointObj)
    if not pointObj then return false end
    if self:CheckIsPortalEvent(pointObj) then return true end
    return false
end

--- 判断是否是传送门事件，如果是传送门事件，不触发，仅做切地图展示
---@param pointObj LxInstancePointObj
function LxDreamTripCtrl:CheckIsPortalEvent(pointObj)
    if not pointObj then return false end
    local eventType = LxDataHelper.GetInsPointEventType(pointObj.refId)
    return eventType and eventType == InstanceTypeEnum.Portal
end

